  ('real-estate-moex-00914', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於房地交易課徵所得稅之稅率規定，下列敘述何者錯誤？ 個人持有房屋、土地之期間在1年以內者，稅率為45% 個人持有房屋、土地之期間超過1年，未逾2年者，稅率為35% 個人持有房屋、土地之期間超過2年，未逾10年者，稅率為25% 個人持有房屋、土地之期間超過10年者，稅率為15%', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
